<template>
  <view class="test-page">
    <view class="header">
      <text class="title">图片选择测试</text>
    </view>
    
    <view class="test-section">
      <button class="test-btn" @click="testImageSelection">测试图片选择</button>
      
      <view class="result-section" v-if="testResult">
        <text class="result-title">测试结果:</text>
        <view class="result-content">
          <text class="result-item">图片路径: {{ testResult.path }}</text>
          <text class="result-item">路径类型: {{ testResult.pathType }}</text>
          <text class="result-item">是否成功: {{ testResult.success ? '是' : '否' }}</text>
          <text class="result-item" v-if="testResult.error">错误信息: {{ testResult.error }}</text>
        </view>
      </view>
    </view>
    
    <view class="tips-section">
      <text class="tips-title">💡 测试说明</text>
      <text class="tips-text">• 点击按钮选择图片进行测试</text>
      <text class="tips-text">• 查看控制台获取详细日志</text>
      <text class="tips-text">• 如果测试失败，请检查图片格式和大小</text>
    </view>
  </view>
</template>

<script>
import { getValidImagePath } from '../../utils/imagePathHelper.js'

export default {
  name: 'TestImage',
  
  data() {
    return {
      testResult: null
    }
  },
  
  methods: {
    testImageSelection() {
      console.log('开始测试图片选择...');
      
      // #ifdef MP-WEIXIN
      uni.chooseMedia({
        count: 1,
        mediaType: ['image'],
        sourceType: ['album', 'camera'],
        success: (res) => {
          if (res.tempFiles && res.tempFiles.length > 0) {
            const path = res.tempFiles[0].tempFilePath;
            this.testImagePath(path);
          }
        },
        fail: (err) => {
          console.error('选择图片失败:', err);
          this.testResult = {
            path: '',
            pathType: 'none',
            success: false,
            error: '选择图片失败'
          };
        }
      });
      // #endif
      
      // #ifndef MP-WEIXIN
      uni.chooseImage({
        count: 1,
        sizeType: ['original', 'compressed'],
        sourceType: ['album', 'camera'],
        success: (res) => {
          if (res.tempFilePaths && res.tempFilePaths.length > 0) {
            const path = res.tempFilePaths[0];
            this.testImagePath(path);
          }
        },
        fail: (err) => {
          console.error('选择图片失败:', err);
          this.testResult = {
            path: '',
            pathType: 'none',
            success: false,
            error: '选择图片失败'
          };
        }
      });
      // #endif
    },
    
    async testImagePath(path) {
      try {
        console.log('测试图片路径:', path);
        
        const validPath = await getValidImagePath(path);
        console.log('路径验证成功:', validPath);
        
        this.testResult = {
          path: validPath,
          pathType: this.getPathType(validPath),
          success: true,
          error: null
        };
        
        uni.showToast({
          title: '测试成功',
          icon: 'success'
        });
        
      } catch (error) {
        console.error('路径验证失败:', error);
        
        this.testResult = {
          path: path,
          pathType: this.getPathType(path),
          success: false,
          error: error.message
        };
        
        uni.showToast({
          title: '测试失败',
          icon: 'none'
        });
      }
    },
    
    getPathType(path) {
      if (!path) return 'empty';
      
      if (path.startsWith('http://tmp/') || path.startsWith('https://tmp/')) {
        return 'temp-http';
      }
      if (path.startsWith('wxfile://tmp/')) {
        return 'temp-wxfile';
      }
      if (path.startsWith('file://tmp/')) {
        return 'temp-file';
      }
      if (path.startsWith('tmp/')) {
        return 'temp-relative';
      }
      
      return 'unknown';
    }
  }
}
</script>

<style scoped>
.test-page {
  padding: 20rpx;
  background-color: #f5f5f5;
  min-height: 100vh;
}

.header {
  text-align: center;
  margin-bottom: 30rpx;
}

.title {
  font-size: 36rpx;
  font-weight: bold;
  color: #333;
}

.test-section {
  background-color: white;
  border-radius: 12rpx;
  padding: 20rpx;
  margin-bottom: 20rpx;
}

.test-btn {
  background-color: #007AFF;
  color: white;
  padding: 20rpx;
  border-radius: 8rpx;
  border: none;
  font-size: 28rpx;
  margin-bottom: 20rpx;
}

.result-section {
  margin-top: 20rpx;
}

.result-title {
  display: block;
  font-size: 28rpx;
  font-weight: bold;
  color: #333;
  margin-bottom: 15rpx;
}

.result-content {
  display: flex;
  flex-direction: column;
  gap: 10rpx;
}

.result-item {
  font-size: 24rpx;
  color: #666;
  word-break: break-all;
}

.tips-section {
  background-color: white;
  border-radius: 12rpx;
  padding: 20rpx;
}

.tips-title {
  display: block;
  font-size: 28rpx;
  font-weight: bold;
  color: #333;
  margin-bottom: 15rpx;
}

.tips-text {
  display: block;
  font-size: 24rpx;
  color: #666;
  line-height: 1.5;
  margin-bottom: 8rpx;
}
</style> 